// Helper JSON parser/tokenizer in C (keeps original parsing helpers)
typedef struct {
    char* s;
    int pos;
    int len;
} Tok;

static void skipWS(Tok* t) {
    while (t->pos < t->len && (t->s[t->pos] == ' ' || t->s[t->pos] == ',' || t->s[t->pos] == '\t' || t->s[t->pos] == '\n' || t->s[t->pos] == '\r')) {
        t->pos++;
    }
}

static char* nextToken(Tok* t) {
    skipWS(t);
    if (t->pos >= t->len) return NULL;
    int start = t->pos;
    if (t->s[t->pos] == '[') {
        int depth = 0;
        while (t->pos < t->len) {
            char c = t->s[t->pos++];
            if (c == '[') depth++;
            else if (c == ']') {
                depth--;
                if (depth == 0) break;
            }
        }
        int token_len = t->pos - start;
        char* token = (char*)malloc(token_len + 1);
        strncpy(token, t->s + start, token_len);
        token[token_len] = '\0';
        return token;
    } else if (t->s[t->pos] == '"') {
        t->pos++;
        while (t->pos < t->len && t->s[t->pos] != '"') t->pos++;
        t->pos++;
        int token_len = t->pos - start;
        char* token = (char*)malloc(token_len + 1);
        strncpy(token, t->s + start, token_len);
        token[token_len] = '\0';
        return token;
    } else {
        while (t->pos < t->len && t->s[t->pos] != ',' && t->s[t->pos] != ']' && t->s[t->pos] != '[') t->pos++;
        int token_len = t->pos - start;
        char* token = (char*)malloc(token_len + 1);
        strncpy(token, t->s + start, token_len);
        token[token_len] = '\0';
        int idx = token_len - 1;
        while (idx >= 0 && token[idx] == ' ') {
            token[idx] = '\0';
            idx--;
        }
        return token;
    }
}

static int parse_int(Tok* t) {
    char* tok = nextToken(t);
    if (!tok) return 0;
    int val = atoi(tok);
    free(tok);
    return val;
}

